+    return uri;
+  }
+
+  private static boolean isZeroAddress(InetAddress address) {
+    byte[] addr = address.getAddress();
+    for (byte b : addr) {
+      if (b != 0) {
+        return false;
+      }
+    }
+    return true;
+  }
+}

